const original = $('Split In Batches').item.json;
const kieStyleUrl = $json.data.downloadUrl;
if (!kieStyleUrl) throw new Error('Style ref upload failed — no downloadUrl in response: ' + JSON.stringify($json).substring(0, 300));
return [{ json: Object.assign({}, original, { kie_style_url: kieStyleUrl }) }];

const item = $input.first().json;
const refs = [];
if (item.kie_style_url) refs.push(item.kie_style_url);

const fullPrompt = (item.style_guide || '') +
  '\n\nSPECIFIC CONTENT FOR THIS IMAGE:\n' + item.resolved_prompt +
  '\n\nReference the provided style image to maintain visual consistency in palette, illustration style, and layout.';

return [{ json: Object.assign({}, item, {
  full_prompt: fullPrompt,
  kie_body: {
    model: 'gpt-image-2-image-to-image',
    input: {
      prompt: fullPrompt,
      input_urls: refs,
      aspect_ratio: '4:5'
    }
  }
}) }];

const fileId       = $('Upload to Drive').item.json.id;
const originalItem = $('Evaluate Poll Status').item.json;
const directLink   = 'https://drive.google.com/uc?id=' + fileId;

return [{ json: Object.assign({}, originalItem, {
  drive_file_id:  fileId,
  drive_link:     directLink,
  image_formula:  '=IMAGE("' + directLink + '")',
  final_status:   'Pending Review',
  status:         'done'
}) }];

const config = $('Read Config Sheet').all();
const configMap = {};
config.forEach(item => { configMap[item.json.category] = item.json; });

const staging = $('Read Staging Sheet').all();
const review  = $('Read Review Sheet').all();

const approvedStaging = staging.filter(i => {
  const approved = i.json.your_approval === true || String(i.json.your_approval).toUpperCase() === 'TRUE';
  const pending  = (i.json.status || '').toLowerCase() === 'pending_review';
  return approved && pending;
});

const needsRefinement = review.filter(i =>
  (i.json.status || '').toLowerCase() === 'needs refinement'
);

const merged = [];

approvedStaging.forEach(item => {
  const cfg = configMap[item.json.category] || {};
  const content = item.json.concept || item.json.final_prompt || '';
  merged.push(Object.assign({}, item.json, {
    source: 'new',
    resolved_prompt: content,
    style_guide: cfg.style_guide || '',
    style_ref_url: cfg.style_ref_url || ''
  }));
});

needsRefinement.forEach(item => {
  const cfg     = configMap[item.json.category] || {};
  const notes   = item.json.refinement_notes || '';
  const content = item.json.concept || item.json.final_prompt || '';
  const prompt  = content + (notes ? '\n\nRefinement notes: ' + notes : '');
  merged.push(Object.assign({}, item.json, {
    source: 'refinement',
    resolved_prompt: prompt,
    style_guide: cfg.style_guide || '',
    style_ref_url: cfg.style_ref_url || ''
  }));
});

if (merged.length === 0) {
  throw new Error('Nothing to process. Approve rows in Staging or mark rows as Needs Refinement in Review.');
}

return merged.map(item => ({ json: item }));

const submit = $json;
const item   = $('Build Kie Request').item.json;

const taskId = (submit.data && submit.data.taskId) || submit.taskId;
if (!taskId) throw new Error('No taskId in Kie response: ' + JSON.stringify(submit).substring(0, 300));

return [{ json: Object.assign({}, item, {
  taskId,
  poll_count: 0,
  next_action: 'retry',
  result_image_url: null
}) }];

const statusData = $json;
const prior      = $('Wait Before Poll').item.json;
const polls      = (prior.poll_count || 0) + 1;

const d     = (statusData && statusData.data) || {};
const state = d.state;

// Try both known result URL paths
const result          = JSON.parse(d.resultJson || '{"resultUrls":[]}');
const result_image_url = result.resultUrls[0] || null;


let nextAction;
if (state === 'success') nextAction = 'continue';
else if (state === 'fail') nextAction = 'fail';
else                     nextAction = 'retry';

return [{ json: Object.assign({}, prior, {
  poll_count:       polls,
  next_action:      nextAction,
  result_image_url: result_image_url,
  poll_status:      state || 'unknown'
}) }];

const item = $input.first().json;
return [{ json: Object.assign({}, item, {
  drive_link:    '',
  image_formula: '',
  final_status:  'Generation Failed (polls: ' + item.poll_count + ', status: ' + (item.poll_status || 'unknown') + ')'
}) }];
